queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?cocktail_lounges a :cocktail_lounges .
    ?cocktail_lounges p:name ?name .
    ?cocktail_lounges p:hours ?hours_f .
    FILTER(STR(?hours_f) = "Open from 5 PM to 2 AM")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?sports_bars a :sports_bars .
    ?sports_bars p:name ?name .
    ?sports_bars p:hours ?hours_f .
    FILTER(STR(?hours_f) = "Open from 5 PM to 2 AM")
    BIND(?name AS ?o0)
  }
}

